import React from 'react'
import styles from './Intro2.module.scss'

const skills = [
    'React',
    'React-Native',
    'Redux',
    'Redux-saga',
    'React-Context',
    'React-Hooks',
    'TypeScript',
    'Node.js',
    'Immer',
    'Immutable',
    'Express',
    'Axios',
    'SASS(SCSS)',
    'Styled-Components',
    'MongoDb'
]
const Intro2 = props => {
    // const {
    //   lang,
    // } = props
    return (
        <div className={styles.intro}>
            <h2>Front-end Developer</h2>
            {/* <div>{lang.skills}</div> */}
            <h4>
                {skills.map((m, i) => (
                    <p key={i}>{m}</p>
                ))}
            </h4>
        </div>
    )
}

export default Intro2
