import React from 'react';
import styles from './SkillsText.module.scss';

const SkillsText = (props) => {
  const {
    skills
  } = props
  return (
    <div className={styles.skills}>
      {skills.map((m, i) => <span key={i}>{m}</span>)}
    </div>
  );
};

export default SkillsText;