import React from 'react';
import styles from './MenuText.module.scss';

const MenuText = (props) => {
  const {
    title,
    id
  } = props
  return (
    <div className={styles.wrapper} id={id}>
      <div className={styles.title}>
        <p>
          {title}
        </p>
        <br />
      </div>
    </div>
  );
};

export default MenuText;