import React from 'react';
import { Icon } from 'antd';
import styles from './Button.module.scss';

const Button = (props) => {
  const {
    title,
  } = props
  return (
    <div className={styles.btn}>
      <a href="https://github.com/kdilot" target="_blank" rel="noopener noreferrer">
        <Icon type="github" style={{ display: 'flex', alignItems: 'center', fontSize: '1.8rem', paddingRight: '1rem' }} />
        {title}
        <Icon type="arrow-right" style={{ display: 'flex', alignItems: 'center', fontSize: '1rem', paddingLeft: '1rem' }} />
      </a>
    </div>
  );
};

export default Button;